#include<bits/stdc++.h>
#define int long long
using namespace std;
//0是上面，1是左边，2是下边
int dp[1005][1005][3], a[1005][1005]; 
const int inf = 1e10 + 10;
signed main()
{
	int n, m;
	cin >> n >> m;
	for(int i = 1; i <= n; i++)
		for(int j = 1; j <= m; j++)
			cin >> a[i][j];
	for(int i = 0; i <= 1004; i++)
		for(int j = 0; j <= 1004; j++)
			dp[i][j][0] = dp[i][j][1] = dp[i][j][2] = -inf;
	dp[1][1][0] = dp[1][1][1] = dp[1][1][2] = a[1][1];
	for(int i = 1; i <= m; i++){
		for(int j = 1; j <= n; j++){
		//	if(i == j && i == 1)continue;
			dp[j][i][1] = max(dp[j][i - 1][0], max(dp[j][i - 1][1], dp[j][i - 1][2])) + a[j][i];
		}
		for(int j = 2; j <= n; j++){
//			if(i == j && i == 1)continue;
			dp[j][i][0] = max(dp[j - 1][i][1], dp[j - 1][i][0]) + a[j][i];
		}

		for(int j = n - 1; j >= 1; j--){
		//	if(i == j && i == 1)continue;
			dp[j][i][2] = max(dp[j + 1][i][1], dp[j + 1][i][2]) + a[j][i];
		}
	}

		//从上面转移 





//	for(int i = 1; i <= n; i++){
//		for(int j = 1; j <= m; j++)
//			cout << "(" << dp[i][j][0] << " " << dp[i][j][1] << " " << dp[i][j][2] << ")";
//		cout << endl;
//	}
	cout << max(dp[n][m][0], dp[n][m][1]);
}
